"usage":"SELECT day, SUM(usage_units) usage, COUNT(DISTINCT customer_id) users FROM daily_usage WHERE day>=78 AND day<=84 GROUP BY day ORDER BY day",
"social":"SELECT post_id, day, content FROM social_media_posts WHERE day>=78 ORDER BY day, post_id"
}
for name,q in queries.items():
    print("--",name)
    r=nm.query(q)
    for row in r["rows"]: print(row)
'

