arguments.cmd:
./novamind-operation python-c '
import novamind_api as nm
queries={
"issues":"SELECT group_id, COUNT(*) n, MIN(open_day) min_day, MAX(open_day) max_day, ROUND(AVG(days_open),2) avg_days_open FROM issues WHERE status=\"open\" GROUP BY group_id ORDER BY n DESC",
"resolved":"SELECT group_id, COUNT(*) n, ROUND(AVG(resolved_day-open_day),2) avg_days FROM issues WHERE resolved_day>=141 AND resolved_day<=147 GROUP BY group_id ORDER BY n DESC",
"usage":"SELECT day, SUM(usage_units) usage, COUNT(DISTINCT customer_id) users FROM daily_usage WHERE day>=141 AND day<=147 GROUP BY day ORDER BY day",
"social":"SELECT post_id, day, content FROM social_media_posts WHERE day>=141 ORDER BY day, post_id"
}
for name,q in queries.items():
    print("--",name)
    r=nm.query(q)
    for row in r["rows"]: print(row)
'

